use inference::mapping::MappingDictionary;
use inference::ner::EntitySpan;
use inference::redact::{redact, rehydrate};

/// Tests for redact() and rehydrate() functions in inference/src/redact.rs
/// Generated by Agent B for comprehensive coverage of redaction logic

// ============================================================================
// HAPPY PATH TESTS
// ============================================================================

#[test]
fn test_redact_happy_path_single_bert_entity() {
    let text = "My name is John Smith.";
    let bert_spans = vec![EntitySpan {
        text: "John Smith".to_string(),
        label: "PER".to_string(),
        start: 11,
        end: 21,
    }];

    let (redacted, mapping) = redact(text, bert_spans, &[]).unwrap();

    assert_eq!(redacted, "My name is [PER_1].");
    assert_eq!(mapping.mappings.len(), 1);
    assert_eq!(mapping.mappings.get("[PER_1]"), Some(&"John Smith".to_string()));
}

#[test]
fn test_redact_happy_path_multiple_bert_entities() {
    let text = "Alice works at Microsoft in Seattle.";
    let bert_spans = vec![
        EntitySpan {
            text: "Alice".to_string(),
            label: "PER".to_string(),
            start: 0,
            end: 5,
        },
        EntitySpan {
            text: "Microsoft".to_string(),
            label: "ORG".to_string(),
            start: 15,
            end: 24,
        },
        EntitySpan {
            text: "Seattle".to_string(),
            label: "LOC".to_string(),
            start: 28,
            end: 35,
        },
    ];

    let (redacted, mapping) = redact(text, bert_spans, &[]).unwrap();

    assert_eq!(redacted, "[PER_1] works at [ORG_1] in [LOC_1].");
    assert_eq!(mapping.mappings.len(), 3);
    assert_eq!(mapping.mappings.get("[PER_1]"), Some(&"Alice".to_string()));
    assert_eq!(mapping.mappings.get("[ORG_1]"), Some(&"Microsoft".to_string()));
    assert_eq!(mapping.mappings.get("[LOC_1]"), Some(&"Seattle".to_string()));
}

