#[test]
fn test_skipped_entities_multiple() {
    let text = "Alice at alice@example.com, SSN 123-45-6789";
    let bert_spans = vec![EntitySpan {
        text: "Alice".to_string(),
        label: "PER".to_string(),
        start: 0,
        end: 5,
    }];

    let (redacted, mapping) = redact(text, bert_spans, &["PER".to_string(), "EMAIL".to_string()]).unwrap();

    // PER and EMAIL skipped, only SSN redacted
    assert_eq!(redacted, "Alice at alice@example.com, SSN [SSN_1]");
    assert_eq!(mapping.mappings.len(), 1);
}

#[test]
fn test_skipped_entities_preserves_conflict_resolution() {
    // Even when an entity is skipped, conflict resolution should have
    // already happened before filtering. This ensures disabled entities
    // don't cause suppressed BERT entities to incorrectly survive.
    let text = "SSN: 123-45-6789";
    let bert_spans = vec![EntitySpan {
        text: "123-45-6789".to_string(),
        label: "PER".to_string(),
        start: 5,
        end: 16,
    }];

    // Skip SSN (regex-authoritative winner) — BERT PER should also be suppressed
    let (redacted, mapping) = redact(text, bert_spans, &["SSN".to_string()]).unwrap();

    // Both entities detected same span: regex SSN won conflict resolution,
    // then SSN was filtered. BERT PER was never added to all_spans due to
    // conflict. So no redaction happens.
    // CORRECTION: skipped_entities filters BEFORE conflict resolution in this impl.
    // The code filters during span collection (lines 129, 142), not after merge.
    // So: regex SSN is skipped → BERT PER is added → redacted as PER.
    assert_eq!(redacted, "SSN: [PER_1]");
    assert_eq!(mapping.mappings.len(), 1);
}

