// ============================================================================
// TOKEN FORMAT TESTS
// ============================================================================

#[test]
fn test_token_format_label_underscore_number() {
    let text = "Alice and Bob";
    let bert_spans = vec![
        EntitySpan {
            text: "Alice".to_string(),
            label: "PER".to_string(),
            start: 0,
            end: 5,
        },
        EntitySpan {
            text: "Bob".to_string(),
            label: "PER".to_string(),
            start: 10,
            end: 13,
        },
    ];

    let (redacted, mapping) = redact(text, bert_spans, &[]).unwrap();

    assert!(redacted.contains("[PER_1]"));
    assert!(redacted.contains("[PER_2]"));
    assert!(mapping.mappings.contains_key("[PER_1]"));
    assert!(mapping.mappings.contains_key("[PER_2]"));
}

#[test]
fn test_token_format_different_labels() {
    let text = "Alice at Microsoft";
    let bert_spans = vec![
        EntitySpan {
            text: "Alice".to_string(),
            label: "PER".to_string(),
            start: 0,
            end: 5,
        },
        EntitySpan {
            text: "Microsoft".to_string(),
            label: "ORG".to_string(),
            start: 9,
            end: 18,
        },
    ];

    let (redacted, mapping) = redact(text, bert_spans, &[]).unwrap();

    assert!(redacted.contains("[PER_1]"));
    assert!(redacted.contains("[ORG_1]"));
}
